def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45.0 + np.log1p(cap) * 30
        fluctuation = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.3)
            if cap > 15:
                base_priority += 120 * np.cbrt(cap) + 25 * np.sin(cap * 2.1)
            else:
                base_priority -= 50 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.cos(usage * np.pi * i * 0.75) * 18 / (i + 1)
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2200 * delta ** 2 + 250 * (1 - delta ** 0.6)
            for j in range(1, 10):
                fluctuation += np.sin(usage * np.pi * (j ** 1.4)) * 20 / (j + 1)
            if int(cap * 4.2) % 4 == 1:
                base_priority += 45 * np.tan(cap / 18)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3)**2
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 12 / (k + 1)
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 11 and usage > 3.5:
                        fluctuation += 25
            if cap % 3.2 < 0.7:
                base_priority += 45 * np.sin(cap * 2.1)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2) ** 2.5
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.65:
                    fluctuation += pwr * 20 / (m + 1)
                    if m % 4 == 3:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 14 / (m + 2)
                    if m == 14 and usage > 2.7:
                        fluctuation += 18
            if cap % 1.8 < 0.4:
                base_priority += 32 * np.cos(cap * 3.5)
        elif 1 < usage <= 2:
            base_priority += 950 * (usage - 1) ** 3.3
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.7:
                    fluctuation += pwr * 28 / (n + 1)
                    if n % 5 == 2:
                        fluctuation -= 3.5 * n
                else:
                    fluctuation += (1 - pwr) * 14 / (n + 3)
                    if n == 15 and usage > 1.8:
                        fluctuation += 22
            if cap % 1.3 < 0.35:
                base_priority += 30 * np.cos(cap * 2.3)
        elif 0.75 < usage <= 1:
            base_priority += 140 * (1 - usage)
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 14 / o
                if usage < 0.05 * o:
                    fluctuation -= 9 * o
            if cap < 0.1:
                base_priority += np.sqrt(cap) * 300
            elif cap < 0.9:
                base_priority += np.log1p(cap * 22) * 38
            else:
                base_priority += (cap % 6) * 25
        elif 0.5 < usage <= 0.75:
            base_priority += 200 * (0.75 - usage) ** 2
            for p in range(1, 10):
                pwr = usage ** p
                fluctuation += (np.cos(pwr * np.pi / 4) - 0.2) * 16 / p
                if usage < 0.03 * p:
                    fluctuation -= 10 * p
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 270
            elif cap < 0.8:
                base_priority += np.log1p(cap * 18) * 33
            else:
                base_priority += (cap % 7) * 28
        elif 0.25 < usage <= 0.5:
            base_priority += 220 * (0.5 - usage)
            for q in range(1, 15):
                pwr = usage ** q
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 15 / q
                if usage < 0.02 * q:
                    fluctuation -= 11 * q
            if cap < 0.18:
                base_priority += np.sqrt(cap) * 260
            elif cap < 0.75:
                base_priority += np.log1p(cap * 15) * 30
            else:
                base_priority += (cap % 8) * 26
        else:
            base_priority += 300 * (1 - usage) ** 3
            for r in range(1, 20):
                pwr = usage ** r
                fluctuation += (np.cos(pwr * np.pi / 7) - 0.3) * 14 / r
                if usage < 0.01 * r:
                    fluctuation -= 13 * r
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 350
            elif cap < 0.95:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 10) * 35
        priority = base_priority + fluctuation
        if cap < 0.03:
            priority += 85
            if usage > 0.72:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for s in range(1, 8):
                    priority -= s * np.exp(-usage * 25)
        elif cap < 1:
            priority += 45
            if usage > 0.88:
                priority += 70
            elif usage < 0.25:
                priority -= 35
            for t in range(1, 7):
                if int(cap * 1300) % (t + 5) == 1:
                    priority += t * 8
                else:
                    priority -= t * 4
        else:
            if usage < 0.1:
                priority -= 50
                for u in range(1, 8):
                    priority -= u * 6
            elif usage > 0.93:
                priority += 95
                for v in range(1, 6):
                    priority += v * 11
            else:
                priority += 35
        proximity = 0
        if int(cap * 2700) % 21 == 0:
            proximity += 18
        if int(cap * 850) % 25 == 0:
            proximity -= 13
        if int(cap * 200) % 11 == 0:
            proximity += 16
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.018:
                proximity += 22 / w
            elif diff < 0.045:
                proximity += 13 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 11)
            if mod_chk == 1:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1800) % (y + 7)
            if mod_chk == 1:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.004:
            for z in range(1, 10):
                priority -= z * 11
        elif usage > 0.96:
            for aa in range(1, 8):
                priority += aa * 13
        if cap > 3.0:
            if cap % 1 < 0.05:
                priority += 45
            if (int(cap * 2600) % 25 == 0) and (usage > 0.75):
                priority += 70
            for bb in range(1, 7):
                if (int(cap * 650) % (bb + 11) == 3) and (usage < 0.88):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
